String getAmountDisplay(MakeOffer offer, bool isVendorView) {
  // For Nigerian to Nigerian
  if (!offer.isInternationalVendor) {
    return formatCurrency(offer.finalTotalCost > 0 
      ? offer.finalTotalCost 
      : offer.chats.last.counterTotalCost, 'NGN');
  }

  // For International vendor
  if (isVendorView) {
    // Vendor sees USD
    double usdAmount = offer.finalTotalCostUSD > 0 
      ? offer.finalTotalCostUSD 
      : (offer.chats.last.counterTotalCost * offer.exchangeRate);
    return formatCurrency(usdAmount, 'USD');
  } else {
    // Buyer sees NGN
    return formatCurrency(offer.finalTotalCost > 0 
      ? offer.finalTotalCost 
      : offer.chats.last.counterTotalCost, 'NGN');
  }
}

Widget buildAmountInfo(MakeOffer offer) {
  return Column(
    children: [
      // Buyer's view
      Text(
        'Buyer pays: ${formatCurrency(offer.finalTotalCost, "NGN")}',
        style: TextStyle(fontWeight: FontWeight.bold),
      ),
      // Vendor's view (if international)
      if (offer.isInternationalVendor)
        Text(
          'Vendor receives: ${formatCurrency(offer.finalTotalCostUSD, "USD")}',
          style: TextStyle(color: Colors.grey[600]),
        ),
      // Exchange rate info
      if (offer.isInternationalVendor)
        Text(
          'Exchange rate: ${offer.exchangeRate}',
          style: TextStyle(fontSize: 12, color: Colors.grey),
        ),
    ],
  );
}
